32	static void print_cpu_configuration()
33	{
34	  // these symbols are defined in obj_sc/config.o
35	  // they come from andes_ip/kv_core/top/hdl/config.inc
36	  char* start = &_binary_config_inc_start;
37	  char* end = &_binary_config_inc_end;
38	  fwrite(start, 1, end - start, stdout);
39	}
