134	extern "C" auto sc_main(const int argc, char* argv[]) -> int
135	try {
136	  spdlog::set_default_logger(spdlog::stderr_color_mt("stderr_logger"));
137	  spdlog::set_pattern("[%^%l%$] %v");
138	
139	  const auto args = [&] {
140	    struct args
141	    {
142	      std::string pc_trace_file{};
143	      std::string elf_file{};
144	      std::optional<uint16_t> jtag_port = std::nullopt;
145	      bool memmap = false;
146	      std::string waveform_file{};
147	      unsigned mem_latency = 1;
148	      std::string ilm_file{};
149	      std::string dlm_file{};
150	      std::string kanata_file{};
151	      std::string objdump_file{};
152	      std::string clarity_file{};
153	      std::optional<uint64_t> kanata_loop_start{};
154	      std::optional<uint64_t> kanata_loop_end{};
155	      uint64_t kanata_loop_skip = 0;
156	      uint64_t kanata_loop_record = 1;
157	      std::vector<std::string> reset_vectors{};
158	      bool continue_ctx = false;
159	      bool save_ctx = false;
160	      std::string context_dir = "./saved_ctx/";
161	      std::string shared_mem_path{};
162	      uint64_t shared_mem_size = 0;
163	      uint64_t shared_mem_base = 0x80000000;
164	      std::string resume_from_qemu{};
165	      std::string handoff_out{};
166	      std::string qemu_binary{};
167	      std::optional<uint64_t> hybrid_enter_pc{};
168	      std::optional<uint64_t> hybrid_exit_pc{};
169	      std::optional<uint64_t> hybrid_icount{};
170	    } args;
171	
172	    const auto help_and_exit = [] {
173	      print_help();
174	      exit(0);
175	    };
176	
177	    auto p = parser{};
178	    p.shortflag('h', help_and_exit);
179	    p.longflag("help", help_and_exit);
180	    p.longflag("version", [] {
181	      print_version();
182	      exit(0);
183	    });
184	    p.longflag("print-memmap", [&] { args.memmap = true; });
185	    p.longflag("print-config", [] {
186	      print_cpu_configuration();
187	      exit(0);
188	    });
189	    p.longopt("jtag-port", [&](const std::string_view s) {
190	      if (auto n = to_int<uint16_t>(s); n)
191	        args.jtag_port = *n;
192	      else
193	        throw std::runtime_error("invalid number for --jtag-port: "
194	                                 + std::string{s});
195	    });
196	    p.longopt("mem-latency", [&](const std::string_view s) {
197	      if (auto n = to_int<unsigned>(s); n)
198	        args.mem_latency = *n;
199	      else
200	        throw std::runtime_error("invalid number for --mem-latency: "
201	                                 + std::string{s});
202	    });
203	    p.longopt("log-level", [](const std::string_view s) {
204	      if (auto n = to_int<uint16_t>(s); n) {
205	        *n = std::min(*n, (uint16_t) SPDLOG_LEVEL_OFF);
206	        spdlog::set_level(static_cast<spdlog::level::level_enum>(*n));
207	      } else {
208	        throw std::runtime_error("invalid number for --log-level: "
209	                                 + std::string{s});
210	      }
211	    });
212	    p.longopt("waveform",
213	              [&](const std::string_view s) { args.waveform_file = s; });
214	    p.longopt("ilm", [&](const std::string_view s) { args.ilm_file = s; });
215	    p.longopt("dlm", [&](const std::string_view s) { args.dlm_file = s; });
216	    p.longopt("pc-trace",
217	              [&](const std::string_view s) { args.pc_trace_file = s; });
218	    p.longopt("kanata",
219	              [&](const std::string_view s) { args.kanata_file = s; });
220	    p.longopt("objdump",
221	              [&](const std::string_view s) { args.objdump_file = s; });
222	    p.longopt("clarity",
223	              [&](const std::string_view s) { args.clarity_file = s; });
224	    p.longopt("kanata-loop-start", [&](const std::string_view s) {
225	      try {
226	        args.kanata_loop_start = std::stoull(std::string{s}, nullptr, 0);
227	      } catch (...) {
228	        throw std::runtime_error("invalid --kanata-loop-start: "
229	                                 + std::string{s});
230	      }
231	    });
232	    p.longopt("kanata-loop-end", [&](const std::string_view s) {
233	      try {
234	        args.kanata_loop_end = std::stoull(std::string{s}, nullptr, 0);
235	      } catch (...) {
236	        throw std::runtime_error("invalid --kanata-loop-end: "
237	                                 + std::string{s});
238	      }
239	    });
240	    p.longopt("kanata-loop-skip", [&](const std::string_view s) {
241	      try {
242	        args.kanata_loop_skip = std::stoull(std::string{s}, nullptr, 0);
243	      } catch (...) {
244	        throw std::runtime_error("invalid --kanata-loop-skip: "
245	                                 + std::string{s});
246	      }
247	    });
248	    p.longopt("kanata-loop-record", [&](const std::string_view s) {
249	      try {
250	        args.kanata_loop_record = std::stoull(std::string{s}, nullptr, 0);
251	      } catch (...) {
252	        throw std::runtime_error("invalid --kanata-loop-record: "
253	                                 + std::string{s});
254	      }
255	    });
256	    p.longflag("continue", [&] { args.continue_ctx = true; });
257	    p.longflag("save", [&] { args.save_ctx = true; });
258	    p.longopt("context-dir",
259	              [&](const std::string_view s) { args.context_dir = s; });
260	    p.longopt("shared-mem-path",
261	              [&](const std::string_view s) { args.shared_mem_path = s; });
262	    p.longopt("shared-mem-size", [&](const std::string_view s) {
263	      try {
264	        args.shared_mem_size = std::stoull(std::string{s}, nullptr, 0);
265	      } catch (...) {
266	        throw std::runtime_error("invalid --shared-mem-size: "
267	                                 + std::string{s});
268	      }
269	    });
270	    p.longopt("shared-mem-base", [&](const std::string_view s) {
271	      try {
272	        args.shared_mem_base = std::stoull(std::string{s}, nullptr, 0);
273	      } catch (...) {
274	        throw std::runtime_error("invalid --shared-mem-base: "
275	                                 + std::string{s});
276	      }
277	    });
278	    p.longopt("resume-from-qemu", [&](const std::string_view s) {
279	      args.resume_from_qemu = s;
280	    });
281	    p.longopt("handoff-out", [&](const std::string_view s) {
282	      args.handoff_out = s;
283	    });
284	    p.longopt("qemu-binary", [&](const std::string_view s) {
285	      args.qemu_binary = s;
286	    });
287	    p.longopt("hybrid-enter-pc", [&](const std::string_view s) {
288	      try {
289	        args.hybrid_enter_pc = std::stoull(std::string{s}, nullptr, 0);
290	      } catch (...) {
291	        throw std::runtime_error("invalid --hybrid-enter-pc: "
292	                                 + std::string{s});
293	      }
294	    });
295	    p.longopt("hybrid-exit-pc", [&](const std::string_view s) {
296	      try {
297	        args.hybrid_exit_pc = std::stoull(std::string{s}, nullptr, 0);
298	      } catch (...) {
299	        throw std::runtime_error("invalid --hybrid-exit-pc: "
300	                                 + std::string{s});
301	      }
302	    });
303	    p.longopt("hybrid-icount", [&](const std::string_view s) {
304	      try {
305	        args.hybrid_icount = std::stoull(std::string{s}, nullptr, 0);
306	      } catch (...) {
307	        throw std::runtime_error("invalid --hybrid-icount: "
308	                                 + std::string{s});
309	      }
310	    });
311	    p.longopt("reset-vector", [&](const std::string_view s) {
312	      args.reset_vectors.emplace_back(s);
313	    });
314	    p.posarg([&](const std::string_view s) { args.elf_file = s; });
315	    p.parse(std::vector<std::string_view>(argv, argv + argc));
316	    return args;
317	  }();
318	
319	#ifndef VSIMSAVABLE
320	  if (args.save_ctx || args.continue_ctx || args.context_dir != "./saved_ctx/")
321	  {
322	    spdlog::critical(
323	      "--save, --continue, and --context-dir require VSIMSAVABLE build");
324	    std::exit(EXIT_FAILURE);
325	  }
326	#endif
327	
328	  if (!args.resume_from_qemu.empty() && args.continue_ctx)
329	    throw std::runtime_error(
330	      "--resume-from-qemu and --continue are mutually exclusive");
331	
332	  print_version();
333	
334	  // systemc and cci init
335	  auto broker = cci_utils::broker{"global_broker"};
336	  cci::cci_register_broker(broker);
337	
338	  const auto time_resolution = sc_core::sc_get_time_resolution();
339	  spdlog::debug("Using time resolution: {}", time_resolution.to_string());
340	
341	  std::optional<MmapBacking> shared_ram;
342	  if (!args.shared_mem_path.empty()) {
343	    if (args.shared_mem_size == 0)
344	      throw std::runtime_error(
345	        "--shared-mem-path requires --shared-mem-size > 0");
346	    shared_ram.emplace(args.shared_mem_path, args.shared_mem_size);
347	  } else if (args.shared_mem_size != 0) {
348	    throw std::runtime_error(
349	      "--shared-mem-size requires --shared-mem-path");
350	  }
351	
352	  // Hybrid mode: the mmap window is the only RAM; QEMU virt has no alias.
353	  const MemoryRegion ram_region = shared_ram
354	    ? MemoryRegion{args.shared_mem_base,
355	                   args.shared_mem_base + args.shared_mem_size - 1}
356	    : MemoryRegion{RAM_BASE, RAM_END};
357	  const MemoryRegion ram_alias_region = shared_ram
358	    ? MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
359	                   SimpleMemory<32>::INVALID_ADDRESS}
360	    : MemoryRegion{RAM_ALIAS_BASE, RAM_ALIAS_END};
361	
362	  // run simulation
363	  const auto do_sim = [&]<typename CPU>() -> int {
364	    Simulator<CPU> sim{
365	      "sim",
366	      shared_ram ? shared_ram->span() : std::span<uint8_t>{},
367	      ram_region, ram_alias_region};
368	
369	    if (args.memmap) {
370	      sim.platform.interconnect.dump_region();
371	      return 0;
372	    }
373	
374	    sim.set_mem_latency(args.mem_latency);
375	
376	    if (!args.ilm_file.empty())
377	      sim.load_image(args.ilm_file, MEM_TYPE::ILM);
378	
379	    if (!args.dlm_file.empty())
380	      sim.load_image(args.dlm_file, MEM_TYPE::DLM);
381	
382	    // End of elaboration
383	    sc_core::sc_start(sc_core::SC_ZERO_TIME);
384	
385	    const auto t0 = std::chrono::steady_clock::now();
386	
387	    if (!args.waveform_file.empty())
388	      sim.enable_waveform(args.waveform_file);
389	
390	    if (!args.pc_trace_file.empty())
391	      sim.enable_pc_trace(args.pc_trace_file);
392	
393	    if (!args.kanata_file.empty() && !args.clarity_file.empty())
394	      throw std::runtime_error("--kanata and --clarity are mutually exclusive");
395	
396	    std::optional<kanata::LoopGate> loop_gate;
397	    if (args.kanata_loop_start.has_value()
398	        != args.kanata_loop_end.has_value())
399	      throw std::runtime_error(
400	        "--kanata-loop-start and --kanata-loop-end must be specified together");
401	    if (args.kanata_loop_start.has_value()) {
402	      if (args.kanata_file.empty() && args.clarity_file.empty())
403	        throw std::runtime_error(
404	          "--kanata-loop-* requires --kanata or --clarity");
405	      if (args.kanata_loop_record == 0)
406	        throw std::runtime_error("--kanata-loop-record must be >= 1");
407	      loop_gate = kanata::LoopGate{*args.kanata_loop_start,
408	                                   *args.kanata_loop_end,
409	                                   args.kanata_loop_skip,
410	                                   args.kanata_loop_record};
411	    }
412	
413	    if (!args.kanata_file.empty())
414	      sim.enable_kanata(args.kanata_file, args.objdump_file, loop_gate);
415	
416	    if (!args.clarity_file.empty())
417	      sim.enable_clarity(args.clarity_file, args.objdump_file, loop_gate);
418	
419	    // In tier-2 hybrid resume, QEMU 1 already loaded the ELF into the
420	    // shared mmap. Re-loading would `std::fill_n(memsz - filesz, 0)` over
421	    // each PT_LOAD's .bss tail, wiping phase-1 writes to static buffers.
422	    // Still parse the ELF to set the reset vector -- between sim.reset()
423	    // and apply_resume_from_qemu's DMI halt, the hart fetches one or two
424	    // instructions from the reset vector; if that address is unmapped
425	    // the bus errors leave the hart in a state the resume cannot recover.
426	    const bool elf_already_in_shared_mmap =
427	      !args.resume_from_qemu.empty() && !args.shared_mem_path.empty();
428	    if (!args.elf_file.empty() && !args.continue_ctx)
429	      sim.load_elf(args.elf_file, /*skip_memory_load=*/elf_already_in_shared_mmap);
430	
431	    // Apply per-hart reset vector overrides (after load_elf sets defaults)
432	    for (const auto& s: args.reset_vectors) {
433	      auto [hart, addr] = parse_reset_vector(s);
434	      if (hart) {
435	        sim.set_reset_vector(*hart, addr);
436	      } else {
437	        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
438	          sim.set_reset_vector(i, addr);
439	      }
440	    }
441	
442	    if (args.continue_ctx)
443	      spdlog::info("You're resuming program from the given context");
444	
445	    if (args.jtag_port)
446	      sim.init_debug_port(args.jtag_port.value());
447	
448	    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx
449	        && args.resume_from_qemu.empty())
450	      throw std::runtime_error(
451	        "Required arg : program, --jtag-port, or --resume-from-qemu");
452	
453	    if (args.continue_ctx || args.save_ctx) {
454	      std::string_view s = args.context_dir;
455	      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
456	        throw std::runtime_error("Error: Path " + std::string{s}
457	                                 + " exists but is not a directory.");
458	      if (!std::filesystem::exists(s)) {
459	        try {
460	          std::filesystem::create_directories(s);
461	        } catch (const std::filesystem::filesystem_error& e) {
462	          throw std::runtime_error(std::string{"Failed to create directory: "}
463	                                   + e.what());
464	        }
465	      }
466	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
467	    }
468	
469	    sim.reset();
470	
471	    if (!args.resume_from_qemu.empty())
472	      sim.apply_resume_from_qemu(args.resume_from_qemu);
473	
474	    if (args.hybrid_enter_pc)
475	      spdlog::warn("--hybrid-enter-pc=0x{:x} ignored: entry trigger is "
476	                   "QEMU's job (use plugin enter_pc= arg)",
477	                   *args.hybrid_enter_pc);
478	
479	    if (!args.handoff_out.empty()) {
480	      if (args.hybrid_icount && args.hybrid_exit_pc)
481	        throw std::runtime_error(
482	          "--hybrid-icount and --hybrid-exit-pc are mutually exclusive");
483	      if (args.hybrid_icount)
484	        sim.enable_hybrid_icount_handoff(args.handoff_out,
485	                                         *args.hybrid_icount);
486	      else if (args.hybrid_exit_pc)
487	        sim.enable_hybrid_handoff(args.elf_file, args.handoff_out,
488	                                  *args.hybrid_exit_pc);
489	      else
490	        sim.enable_hybrid_handoff(args.elf_file, args.handoff_out);
491	    }
492	
493	    const int exit_code = sim.run();
494	
495	    sim.cpu.final();
496	
497	    if (exit_code == hybrid::kExitHandoffToQemu && !args.qemu_binary.empty()) {
498	      hybrid_state_v1 state{};
499	      std::ifstream sf(args.handoff_out, std::ios::binary);
500	      if (!sf)
501	        throw std::runtime_error("handoff: cannot read drained state file: "
502	                                 + args.handoff_out);
503	      sf.read(reinterpret_cast<char*>(&state), sizeof(state));
504	      if (!sf)
505	        throw std::runtime_error("handoff: short read of drained state file");
506	      return hybrid::run_qemu_handback(args.qemu_binary, args.elf_file, state,
507	                                       args.shared_mem_path,
508	                                       args.shared_mem_size);
509	    }
510	
511	    const auto t1 = std::chrono::steady_clock::now();
512	    const auto cycles = sim.get_cycles();
513	    spdlog::info("{} cycles simulated", cycles);
514	    if (cycles > 0) {
515	      const auto ms =
516	        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
517	      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
518	                   ms.count() % 1000,
519	                   double(cycles) / double(ms.count()) * 1000.0);
520	    }
521	    return exit_code;
522	  };
523	
524	  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();
525	
