1	// StateDrain halts the hart via the Debug Module and populates a
2	// hybrid_state_v1 with the architectural register file. Reuses
3	// ResumeDriver's DM register constants and DmiBus interface.
4	
5	#pragma once
6	
7	#include "hybrid/abstract_command.hpp"
8	#include "hybrid/dmi_poll.hpp"
9	#include "hybrid/resume_driver.hpp"
10	#include "hybrid/state_abi.h"
11	
12	#include <algorithm>
13	#include <cstdint>
14	
15	namespace hybrid
16	{
17	
18	class StateDrain
19	{
20	public:
21	  using RD = ResumeDriver;
22	
23	  explicit StateDrain(DmiBus& bus)
24	      : bus_{bus}
25	  {}
26	
27	  // Drain x1..x31 + PC. FP/CSR/V slots remain zero; merge them in via
28	  // drain_with_passthrough when the QEMU 1 snapshot is available.
29	  auto drain() -> hybrid_state_v1
30	  {
31	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive);
32	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolHaltreq);
33	    poll_until_set(bus_, RD::kDmstatus, RD::kDmstatusAllhalted,
34	                   "StateDrain halt");
35	
36	    hybrid_state_v1 state{};
37	    state.magic   = HYBRID_STATE_MAGIC;
38	    state.version = HYBRID_STATE_VERSION;
39	    state.flags   = HYBRID_FLAG_RV64;
40	    state.priv    = 3;
41	
42	    for (uint16_t i = 1; i < 32; ++i)
43	      state.gpr[i] = read_64bit_register(regno_gpr(i));
44	
45	    state.pc = read_64bit_register(regno_csr(RD::kCsrDpc));
46	    return state;
47	  }
48	
49	  // Returns the input snapshot with x1..x31 and PC overwritten by a fresh
50	  // DM read. When HYBRID_FLAG_FP is set, also freshly reads f0..f31 so
51	  // post-vsim FP modifications are captured (otherwise the stale QEMU 1
52	  // snapshot leaks through to QEMU 2). When HYBRID_FLAG_V is set, also
53	  // freshly reads the six V CSRs (vstart/vxsat/vxrm/vcsr/vtype/vl); vlenb
54	  // and vreg remain pass-through (read-only / too large for DM).
55	  auto drain_with_passthrough(const hybrid_state_v1& input) -> hybrid_state_v1
56	  {
57	    auto state       = input;
58	    const auto fresh = drain();
59	    std::copy(std::begin(fresh.gpr) + 1, std::end(fresh.gpr),
60	              std::begin(state.gpr) + 1);
61	    state.pc = fresh.pc;
62	
63	    if (input.flags & HYBRID_FLAG_FP) {
64	      for (uint16_t i = 0; i < 32; ++i)
65	        state.fpr[i] = read_64bit_register(regno_fpr(i));
66	    }
67	
68	    if (input.flags & HYBRID_FLAG_V) {
69	      state.vstart = read_64bit_register(regno_csr(RD::kCsrVstart));
70	      state.vxsat  = read_64bit_register(regno_csr(RD::kCsrVxsat));
71	      state.vxrm   = read_64bit_register(regno_csr(RD::kCsrVxrm));
72	      state.vcsr   = read_64bit_register(regno_csr(RD::kCsrVcsr));
73	      state.vtype  = read_64bit_register(regno_csr(RD::kCsrVtype));
74	      state.vl     = read_64bit_register(regno_csr(RD::kCsrVl));
75	    }
76	
77	    return state;
78	  }
79	
80	private:
81	  auto read_64bit_register(uint16_t regno) -> uint64_t
82	  {
83	    bus_.write(RD::kCommand, access_register_command(regno, AarSize::Bits64,
84	                                                     /*write=*/false));
85	    poll_until_clear(bus_, RD::kAbstractcs, RD::kAbstractcsBusy,
86	                     "StateDrain read_register");
87	    // If the hardware DM does not implement Abstract access for this
88	    // register, cmderr is set sticky and DATA0/DATA1 hold stale bytes.
89	    // Clear the error and report 0 for that field so the next read can
90	    // proceed - a missing CSR mirrors as zero rather than corrupting the
91	    // adjacent slot.
92	    const auto status = bus_.read(RD::kAbstractcs);
93	    if ((status & RD::kAbstractcsCmderrMask) != 0u) {
94	      bus_.write(RD::kAbstractcs, RD::kAbstractcsCmderrMask);
95	      return 0u;
96	    }
97	    const uint64_t lo = bus_.read(RD::kData0);
98	    const uint64_t hi = bus_.read(RD::kData1);
99	    return lo | (hi << 32);
100	  }
101	
102	  DmiBus& bus_;
103	};
