21	class ResumeDriver
22	{
23	public:
24	  static constexpr uint8_t kData0      = 0x04;
25	  static constexpr uint8_t kData1      = 0x05;
26	  static constexpr uint8_t kDmcontrol  = 0x10;
27	  static constexpr uint8_t kDmstatus   = 0x11;
28	  static constexpr uint8_t kAbstractcs = 0x16;
29	  static constexpr uint8_t kCommand    = 0x17;
30	
31	  static constexpr uint16_t kCsrDpc      = 0x7B1;
32	  static constexpr uint16_t kCsrMstatus  = 0x300;
33	  static constexpr uint16_t kCsrMtvec    = 0x305;
34	  static constexpr uint16_t kCsrVstart   = 0x008;
35	  static constexpr uint16_t kCsrVxsat    = 0x009;
36	  static constexpr uint16_t kCsrVxrm     = 0x00A;
37	  static constexpr uint16_t kCsrVcsr     = 0x00F;
38	  static constexpr uint16_t kCsrVtype    = 0xC21;
39	  static constexpr uint16_t kCsrVl       = 0xC20;
40	
41	  static constexpr uint32_t kDmcontrolDmactive  = 1u << 0;
42	  static constexpr uint32_t kDmcontrolResumereq = 1u << 30;
43	  static constexpr uint32_t kDmcontrolHaltreq   = 1u << 31;
44	
45	  static constexpr uint32_t kDmstatusAllhalted    = 1u << 9;
46	  static constexpr uint32_t kDmstatusAllresumeack = 1u << 17;
47	
48	  static constexpr uint32_t kAbstractcsBusy        = 1u << 12;
49	  static constexpr uint32_t kAbstractcsCmderrMask  = 0x7u << 8;
50	
51	  static constexpr unsigned kPollIterations = kDmiPollIterations;
52	
53	  explicit ResumeDriver(DmiBus& bus)
54	      : bus_{bus}
55	  {}
56	
57	  void resume(const hybrid_state_v1& state)
58	  {
59	    if (state.magic != HYBRID_STATE_MAGIC)
60	      throw std::runtime_error("ResumeDriver::resume: bad magic");
61	    if (state.version != HYBRID_STATE_VERSION)
62	      throw std::runtime_error("ResumeDriver::resume: unsupported version");
63	
64	    // dmactive must transition 0->1 in its own write before any other
65	    // DMCONTROL bit is honored (RISC-V Debug Spec).
66	    bus_.write(kDmcontrol, kDmcontrolDmactive);
67	    request_halt();
68	    poll_until_set(bus_, kDmstatus, kDmstatusAllhalted, "ResumeDriver halt");
69	
70	    // mstatus: enable FS / VS so the following FPR / V abstract writes are
71	    // accepted (FS or VS == Off disables the extension and the hart NACKs
72	    // the writes). Single write covers both extensions when present.
73	    const bool fp_needs_fs = (state.flags & HYBRID_FLAG_FP)
74	                          && (state.mstatus & 0x6000u);  // FS = 13:14
75	    const bool v_needs_vs  = (state.flags & HYBRID_FLAG_V)
76	                          && (state.mstatus & 0x600u);   // VS =  9:10
77	    if (fp_needs_fs || v_needs_vs)
78	      write_csr_abstract_or_pb(kCsrMstatus, state.mstatus);
79	
80	    // FPR restore (requires mstatus.FS enabled above).
81	    if (state.flags & HYBRID_FLAG_FP) {
82	      for (uint16_t i = 0; i < 32; ++i)
83	        write_64bit_register(regno_fpr(i), state.fpr[i]);
84	    }
85	
86	    // Tier-A V CSR restore (before GPRs: PB fallback uses x5 as scratch;
87	    // the GPR loop overwrites x5 afterward so state is preserved).
88	    if (state.flags & HYBRID_FLAG_V) {
89	      // Tier-B: vtype+vl via vsetvl x0,x5,x6 in PB.
90	      // Direct csrrw to vtype sets vill; vl is read-only. Stage operands in
91	      // scratch GPRs x5(vl) and x6(vtype) then let vsetvl set both atomically.
92	      // x5/x6 are overwritten by the GPR loop below, so no leakage.
93	      write_64bit_register(regno_gpr(5), state.vl);
94	      write_64bit_register(regno_gpr(6), state.vtype);
95	      const std::array<uint32_t, 1> pb_vsetvl = { encode_vsetvl(0, 5, 6) };
96	      exec_progbuf(bus_, std::span<const uint32_t>{pb_vsetvl});
97	      // vstart must come AFTER vsetvl: vsetvl resets vstart to 0.
98	      write_csr_abstract_or_pb(kCsrVstart, state.vstart);
99	      write_csr_abstract_or_pb(kCsrVxsat,  state.vxsat);
100	      write_csr_abstract_or_pb(kCsrVxrm,   state.vxrm);
101	      write_csr_abstract_or_pb(kCsrVcsr,   state.vcsr);
102	    }
103	
104	    // GPRs + DPC (after V CSRs so PB scratch x5 is safe to overwrite).
105	    for (uint16_t i = 1; i < 32; ++i)
106	      write_64bit_register(regno_gpr(i), state.gpr[i]);
107	    write_64bit_register(regno_csr(kCsrDpc), state.pc);
108	
109	    write_csr_tolerant(kCsrMtvec, state.mtvec);
110	
111	    clear_cmderr_if_set();
112	    request_resume();
113	    poll_until_set(bus_, kDmstatus, kDmstatusAllresumeack,
114	                   "ResumeDriver resume");
115	  }
