128	  void write_64bit_register(uint16_t regno, uint64_t value)
129	  {
130	    bus_.write(kData0, uint32_t(value & 0xffffffffu));
131	    bus_.write(kData1, uint32_t((value >> 32) & 0xffffffffu));
132	    bus_.write(kCommand,
133	               access_register_command(regno, AarSize::Bits64, /*write=*/true));
134	    poll_until_clear(bus_, kAbstractcs, kAbstractcsBusy,
135	                     "ResumeDriver write_register");
136	  }
