475	  auto check_hybrid_handoff() -> std::optional<int>
476	  {
477	    if constexpr (!requires { cpu.get_committed_pc(); }) {
478	      return std::nullopt;
479	    } else {
480	      const auto committed = cpu.get_committed_pc();
481	      if (committed.empty()) return std::nullopt;
482	      auto gpr_probe = [&](uint8_t r) -> uint64_t {
483	        if constexpr (requires { cpu.get_gpr(r); }) {
484	          return cpu.get_gpr(r);
485	        }
486	        return 0;
487	      };
488	      for (const auto pc: committed[0]) {
489	        auto state = std::optional<hybrid_state_v1>{};
490	        if (hybrid_handoff_)
491	          state = hybrid_handoff_->on_retire(pc, gpr_probe);
492	        else if (hybrid_icount_handoff_)
493	          state = hybrid_icount_handoff_->on_retire(pc, gpr_probe);
494	        if (state) {
495	          // V-register merge: the fixture's vsim-phase epilogue is expected
496	          // to have run vse8.v v0..v31 to scratch RAM before the exit
497	          // trigger fired. Read those bytes back into state.vreg[] so the
498	          // gdbstub-driven QEMU 2 restore sees vsim's actual values, not
499	          // QEMU 1's stale snapshot.
500	          if ((state->flags & HYBRID_FLAG_V) != 0u) {
501	            hybrid::read_v_from_scratch(
502	              *state,
503	              std::span<const uint8_t>{platform.main_memory.data.data(),
504	                                       platform.main_memory.data.size()},
505	              platform.main_memory.region.base_address);
506	          }
507	          spdlog::info("hybrid handoff: drained at pc=0x{:x}, writing {}",
508	                       pc, hybrid_state_path_);
509	          std::ofstream f(hybrid_state_path_, std::ios::binary);
510	          f.write(reinterpret_cast<const char*>(&*state), sizeof(*state));
511	          return hybrid::kExitHandoffToQemu;
512	        }
513	      }
514	      return std::nullopt;
515	    }
